//go:build grammar_subset && grammar_subset_thrift

package grammars

func init() {
	Register(LangEntry{
		Name:           "thrift",
		Extensions:     []string{".thrift"},
		Language:       ThriftLanguage,
		GrammarSource:  GrammarSourceTS2GoBlob,
		HighlightQuery: "; Variables\n\n((identifier) @variable\n  (#set! \"priority\" 95))\n\n; Includes\n\n[\n  \"include\"\n  \"cpp_include\"\n] @include\n\n; Function\n\n(function_definition\n  (identifier) @function)\n\n; Fields\n\n(field (identifier) @field)\n\n; Parameters\n\n(function_definition\n  (parameters\n    (parameter (identifier) @parameter)))\n\n(throws\n  (parameters\n    (parameter (identifier) @parameter.exception)))\n\n; Types\n\n(typedef_identifier) @type\n(struct_definition\n  \"struct\" (identifier) @type)\n\n(union_definition\n  \"union\" (identifier) @type)\n\n(exception_definition\n  \"exception\" (identifier) @type)\n\n(service_definition\n  \"service\" (identifier) @type)\n\n(interaction_definition\n  \"interaction\" (identifier) @type)\n\n(type\n  type: (identifier) @type)\n\n(definition_type\n  type: (identifier) @type)\n\n((identifier) @type\n  (#lua-match? @type \"^[_]*[A-Z]\"))\n\n; Constants\n\n(const_definition (identifier) @constant)\n((identifier) @constant\n  (#lua-match? @constant \"^[_A-Z][A-Z0-9_]*$\"))\n(enum_definition \"enum\"\n  . (identifier) @type\n  \"{\" (identifier) @constant \"}\")\n\n; Builtin Types\n\n(primitive) @type.builtin\n\n[\n  \"list\"\n  \"map\"\n  \"set\"\n  \"sink\"\n  \"stream\"\n  \"void\"\n] @type.builtin\n\n; Namespace\n\n(namespace_declaration\n  (namespace_scope) @tag\n  [(namespace) @namespace (_ (identifier) @namespace)])\n\n; Attributes\n\n(annotation_definition\n  (annotation_identifier (identifier) @attribute))\n(fb_annotation_definition\n  \"@\" @attribute (annotation_identifier (identifier) @attribute)\n  (identifier)? @attribute)\n(namespace_uri (string) @attribute)\n\n; Operators\n\n[\n  \"=\"\n  \"&\"\n] @operator\n\n; Exceptions\n\n[\n  \"throws\"\n] @exception\n\n; Keywords\n\n[\n  \"enum\"\n  \"exception\"\n  \"extends\"\n  \"interaction\"\n  \"namespace\"\n  \"senum\"\n  \"service\"\n  \"struct\"\n  \"typedef\"\n  \"union\"\n  \"uri\"\n] @keyword\n\n; Deprecated Keywords\n\n[\n  \"cocoa_prefix\"\n  \"cpp_namespace\"\n  \"csharp_namespace\"\n  \"delphi_namespace\"\n  \"java_package\"\n  \"perl_package\"\n  \"php_namespace\"\n  \"py_module\"\n  \"ruby_namespace\"\n  \"smalltalk_category\"\n  \"smalltalk_prefix\"\n  \"xsd_all\"\n  \"xsd_attrs\"\n  \"xsd_namespace\"\n  \"xsd_nillable\"\n  \"xsd_optional\"\n] @keyword\n\n; Extended Kewords\n[\n  \"package\"\n  \"performs\"\n] @keyword\n\n[\n  \"async\"\n  \"oneway\"\n] @keyword.coroutine\n\n; Qualifiers\n\n[\n  \"client\"\n  \"const\"\n  \"idempotent\"\n  \"optional\"\n  \"permanent\"\n  \"readonly\"\n  \"required\"\n  \"safe\"\n  \"server\"\n  \"stateful\"\n  \"transient\"\n] @type.qualifier\n\n; Literals\n\n(string) @string\n\n(escape_sequence) @string.escape\n\n(namespace_uri\n  (string) @text.uri @string.special)\n\n(number) @number\n\n(double) @float\n\n(boolean) @boolean\n\n; Typedefs\n\n(typedef_identifier) @type.definition\n\n; Punctuation\n\n[\n  \"*\"\n] @punctuation.special\n\n[\"{\" \"}\"] @punctuation.bracket\n\n[\"(\" \")\"] @punctuation.bracket\n\n[\"[\" \"]\"] @punctuation.bracket\n\n[\"<\" \">\"] @punctuation.bracket\n\n[\n  \".\"\n  \",\"\n  \";\"\n  \":\"\n] @punctuation.delimiter\n\n; Comments\n\n(comment) @comment @spell\n\n((comment) @comment.documentation\n  (#lua-match? @comment.documentation \"^/[*][*][^*].*[*]/$\"))\n\n((comment) @comment.documentation\n  (#lua-match? @comment.documentation \"^///[^/]\"))\n((comment) @comment.documentation\n  (#lua-match? @comment.documentation \"^///$\"))\n\n((comment) @preproc\n  (#lua-match? @preproc \"#!.*\"))\n\n; Errors\n\n(ERROR) @error\n",
	})
}
